msg.payload = 
"Player Names: " + msg.payload.players.map(p => p.name);
return msg;

const bet = parseInt(msg.payload);
const winningNumber = Math.floor(Math.random() * 37);

msg.bet = bet;
msg.result = winningNumber;
msg.win = (bet === winningNumber);

return msg;

msg.bet = 2 * msg.bet;

msg.payload = "/give @a minecraft:diamond 25";
return msg;

msg.payload = {
    model: "gpt-4o-mini",
    messages: [
        { role: "system", content: "You are a helpful AI assistant named Gurt. You're purpose is to answer questions and help out people mainly in the game Minecraft." },
        { role: "user", content: msg.payload }
    ]
};
msg.headers = {
    "Content-Type": "application/json",
    "Authorization": ''
};
msg.url = "https://api.openai.com/v1/chat/completions";
return msg;

if (msg.payload && msg.payload.choices && msg.payload.choices[0] && msg.payload.choices[0].message) {
    msg.payload = msg.payload.choices[0].message.content;
} else if (msg.payload && msg.payload.error && msg.payload.error.message) {
    msg.payload = "⚠️ OpenAI Error: " + msg.payload.error.message;
} else {
    msg.payload = "⚠️ Unexpected response from OpenAI API.";
}
return msg;
